const body = $input.first().json.body || $input.first().json;

const email = (body.email || '').toLowerCase().trim();
const firstName = (body.firstName || '').trim();
const phone = (body.phone || '').trim();
const companyName = (body.companyName || '').trim();
const source = (body.source || 'site').trim();
const startedAt = body.startedAt || new Date().toISOString();

const isPriority = source === 'customer';
const priorityLabel = isPriority ? '⚠️ CUSTOMER — URGENT' : 'Site Lead';
const priorityColor = isPriority ? '#dc2626' : '#2AA5A0';

const startedReadable = new Date(startedAt).toLocaleString('en-US', {
  timeZone: 'America/New_York',
  dateStyle: 'medium',
  timeStyle: 'short'
});

const emailSubject = isPriority
  ? '⚠️ URGENT — Customer started checklist: ' + firstName + ' (' + email + ')'
  : 'New checklist lead — started: ' + firstName + ' (' + email + ')';

return [{
  json: {
    email,
    firstName,
    phone,
    companyName,
    source,
    startedAt,
    startedReadable,
    isPriority,
    priorityLabel,
    priorityColor,
    emailSubject,
    hasPhone: phone.length > 0,
    hasCompany: companyName.length > 0
  }
}];
